fn:forward(hidden_states, position_embeddings=None, attention_mask=None, **kwargs)->tuple[torch.Tensor, torch.Tensor|None] = {
  input_shape = hidden_states.shape[:-1]
  qkv = Wqkv(hidden_states) |> view(*input_shape, 3, -1, head_dim) |> unbind(-3) -> query_states,key_states,value_states
  query_states,key_states,value_states = [_.transpose(1,2) for _ in [query_states,key_states,value_states]]
  cos,sin = position_embeddings
  query_states,key_states = apply_rotary_pos_emb(query_states,key_states,cos,sin,unsqueeze_dim=1)
  attention_interface = eager_attention_forward if config._attn_implementation=="eager" else ALL_ATTENTION_FUNCTIONS[config._attn_implementation]
  attn_output,attn_weights = attention_interface(self, query_states, key_states, value_states, attention_mask, dropout=attention_dropout if training else 0.0, scaling=head_dim**-0.5, sliding_window=sliding_window, deterministic=deterministic_flash_attn, **kwargs)
  return attn_output.reshape(*input_shape,-1).contiguous(), out_drop(Wo(attn_output))
}
